    [Fact]    public async Task Test_CompressionBrotliOnly()
    {
        // Tests Brotli compression when enabled and client supports it
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/compression_brotli_only");
        request.Headers.Add("Accept-Encoding", "br");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        Assert.True(response.Headers.TryGetValues("vary", out var hdrvary) && hdrvary.Any(v => v.Contains("Accept-Encoding")), "header vary mismatch");
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"data\":\"aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\",\"message\":\"Brotli compressed payload\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }

